		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;SOM&lt;strong&gt;NAM&lt;/strong&gt;BULI&lt;strong&gt;S&lt;/strong&gt;M&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;NAM&lt;/strong&gt;E&lt;strong&gt;S&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;E&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;नहीं बन सकता है।&amp;nbsp;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;SOMN&lt;strong&gt;A&lt;/strong&gt;M&lt;strong&gt;B&lt;/strong&gt;U&lt;strong&gt;L&lt;/strong&gt;I&lt;strong&gt;S&lt;/strong&gt;M&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;BAS&lt;/strong&gt;A&lt;strong&gt;L&lt;/strong&gt;&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;A&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;नहीं बन सकता&amp;nbsp;&lt;span style=&quot;text-align: center; &quot;&gt;है।&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;S&lt;strong&gt;OM&lt;/strong&gt;NAM&lt;strong&gt;B&lt;/strong&gt;UL&lt;strong&gt;I&lt;/strong&gt;SM&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;BIOM&lt;/strong&gt;E&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;E&lt;/td&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;नहीं बन सकता&amp;nbsp;&lt;span style=&quot;text-align: center; &quot;&gt;है।&lt;/span&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td style=&quot;text-align: center;&quot;&gt;&lt;strong&gt;SO&lt;/strong&gt;MNAMB&lt;strong&gt;UL&lt;/strong&gt;ISM&lt;/td&gt;
